import { useState, useRef, useEffect } from "react";

export default function Sidebar({
    chats,
    activeChatId,
    onNewChat,
    onSelectChat,
    onRenameChat
}) {
    const [editingId, setEditingId] = useState(null);
    const [tempTitle, setTempTitle] = useState("");
    const [menuOpenId, setMenuOpenId] = useState(null);
    const menuRef = useRef(null);

    // 🔒 Lock scroll when menu open (ChatGPT behavior)
    useEffect(() => {
        if (menuOpenId) {
            document.body.style.overflow = "hidden";
        } else {
            document.body.style.overflow = "";
        }
        return () => (document.body.style.overflow = "");
    }, [menuOpenId]);

    // Close on outside click
    useEffect(() => {
        const close = (e) => {
            if (menuRef.current && !menuRef.current.contains(e.target)) {
                setMenuOpenId(null);
            }
        };
        document.addEventListener("mousedown", close);
        return () => document.removeEventListener("mousedown", close);
    }, []);

    const startEdit = (chat) => {
        setEditingId(chat.id);
        setTempTitle(chat.title);
        setMenuOpenId(null);
    };

    const saveEdit = () => {
        if (tempTitle.trim()) {
            onRenameChat(editingId, tempTitle.trim());
        }
        setEditingId(null);
    };

    return (
        <aside className="sidebar">
            <div className="sidebar-header">
                <button className="new-chat-btn" onClick={onNewChat}>
                    ＋ New chat
                </button>
            </div>

            <div className="chat-list">
                {chats.map(chat => (
                    <div
                        key={chat.id}
                        className={`chat-row ${chat.id === activeChatId ? "active" : ""}`}
                        onClick={() => onSelectChat(chat.id)}
                    >
                        {/* TITLE / RENAME */}
                        {editingId === chat.id ? (
                            <input
                                className="chat-rename-input"
                                value={tempTitle}
                                autoFocus
                                onChange={(e) => setTempTitle(e.target.value)}
                                onBlur={saveEdit}
                                onKeyDown={(e) => {
                                    if (e.key === "Enter") saveEdit();
                                    if (e.key === "Escape") setEditingId(null);
                                }}
                            />
                        ) : (
                            <span className="chat-title">{chat.title}</span>
                        )}

                        {/* 3 DOT MENU */}
                        <button
                            className="dots-btn"
                            onClick={(e) => {
                                e.stopPropagation();
                                setMenuOpenId(
                                    menuOpenId === chat.id ? null : chat.id
                                );
                            }}
                        >
                            ⋯
                        </button>

                        {menuOpenId === chat.id && (
                            <>
                                {/* Overlay blocks scrolling */}
                                <div
                                    className="menu-overlay"
                                    onClick={() => setMenuOpenId(null)}
                                />

                                {/* Floating menu */}
                                <div className="chat-menu" ref={menuRef}>
                                    <button onClick={() => startEdit(chat)}>Rename</button>
                                    <button>Share</button>
                                    <button className="danger">Delete</button>
                                </div>
                            </>
                        )}
                    </div>
                ))}
            </div>
        </aside>
    );
}
